        options = "".join(f'<option value="{h(a.get("id"))}">{h(a.get("phone"))}</option>' for a in accounts)
        body = f"""
        <div class="card"><h2>Warmup Profiles</h2><div class="code">{h(profiles)}</div></div>
        <div class="card" style="margin-top:14px"><h2>Run Warmup</h2><form method="post" action="/web/warmup/run"><div class="field"><label>Account</label><select name="account_id">{options}</select></div><div class="field"><label>Actions</label><input name="actions" value="5"></div><button class="btn">Run Warmup</button></form></div>
        """
