    @app.get("/web/scheduler", response_class=HTMLResponse, include_in_schema=False)
    async def scheduler_page(request: Request):
        campaigns = as_dict(await ctx["get_campaigns"]()).get("campaigns", []) if "get_campaigns" in ctx else []
        tasks = as_dict(await ctx["get_scheduled_tasks"]()).get("tasks", []) if "get_scheduled_tasks" in ctx else []
        hours = as_dict(await ctx["get_optimal_hours"]()).get("hours", []) if "get_optimal_hours" in ctx else []
        body = f"""
        <div class="grid3">{stat_card('Campaigns', len(campaigns))}{stat_card('Tasks', len(tasks))}{stat_card('Optimal Hours', len(hours))}</div>
        <div class="card" style="margin-top:14px"><h2>Campaigns</h2>{render_table(campaigns, ['id','name','status','created_at'], 'No campaigns')}</div>
        <div class="card" style="margin-top:14px"><h2>Tasks</h2>{render_table(tasks, ['id','type','status','run_at'], 'No tasks')}</div>
        <div class="card" style="margin-top:14px"><h2>Optimal Hours</h2><div class="code">{h(hours)}</div></div>
        """
        return layout("Scheduler", body, request)

    @app.get("/{full_path:path}", response_class=HTMLResponse, include_in_schema=False)
    async def python_frontend_fallback(full_path: str, request: Request):
        if full_path.startswith("api/"):
            raise HTTPException(status_code=404, detail="API endpoint not found")
        return RedirectResponse(url="/", status_code=303)
